VALUES
  ('aboriginal-f0899a01-moex-00607', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者屬於管轄權競合？ 經濟部國際貿易局委託臺灣鋼鐵工業同業公會簽發原產地證明書 行政院農業委員會指示地方農會協助認定農作物原產地 私立大學經主管教育行政機關依法授權核發學位證書 行為人設立網際網站，違反個人資料保護法，各地方政府相關主管機關享有管轄權', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00608', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '行政機關執行職務時，下列何種情形不得請求協助？ 彰化縣政府就其自治事項，請求內政部移民署協助 臺北市政府就其自治事項，請求新北市政府協助 衛生福利部就其交付高雄市之委辦事項，請求高雄市政府協助 雲林縣政府就中央交付之委辦事項，請求嘉義縣政府協助', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00609', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於司法院大法官釋字第785號解釋之敘述，下列何者正確？ 公務人員基於與國家公法上之職務關係，其作為基本權利主體之身分即與一般人民有所不同 公務人員保障法關於申訴、再申訴之規定，並不排除公務人員得再依法提起相應之行政訴訟之可能， 與憲法訴訟權之保障意旨相違 公務人員保障法第23條規定未就業務性質特殊機關所屬公務人員之超勤補償等事項，設定必要合 理之框架性規範而屬違憲 公務員服務法第11條第2項及公務人員週休二日實施辦法第4條第1項等規定，已就業務性質特 殊機關所屬公務人員勤休方式予以明確規定而屬合憲', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00610', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '新任公務員甲，歲末迎來公務員年終考績，發現下列現象，何者適法正確？ 新進人員一律考績乙等 同等級公務員輪流考績乙等 非主管卻有主管職務代理章公務員，把自己考績打甲等，新進人員打乙等 年終考績甲等晉本俸一級，並給與1個月俸給總額獎金', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00611', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '公務員因公出差浮報差旅費，經刑事法院判決有罪確定後，有關懲戒行為，下列敘述何者正確？ 浮報經費已繳回，不須懲戒 浮報經費已由所屬機關記大過處分，不必再行懲戒 刑罰已確定，不須懲戒 懲戒法院判決浮報經費申誡確定，原機關記大過處分失效', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00612', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '有關政務人員之敘述，下列何者錯誤？ 無須具備公務員任用資格  政務人員之懲戒僅有撤職 政務人員不受身分保障  內政部部長為政務人員', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00613', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '公務員對下列何者不得提起行政訴訟救濟？ 請求原服務機關核發服務年資證明被拒 年終考績被列為丙等 由主管人員調為同機關、以原職等、敘原俸級及同一升遷序列之非主管人員，以致不能領取主管加給 請求領取福利互助金', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00614', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '有關公務員懲處之敘述，下列何者正確？ 由公務員所屬機關之長官發動並處分 政務官假日酒駕之行為應受懲處 不服懲處處分之公務員得向公務人員保障暨培訓委員會提起申訴 懲處處分應由考試院審定', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00615', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '公務人員年終考績78分，屬於下列何等第？ 甲等  乙等  丙等  丁等', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00616', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '有關公物及公營造物使用之敘述，下列何者錯誤？ 公物使用關係之性質，縱有收取費用，亦非必然屬私經濟關係 公有市場與利用人間之法律關係，依據實務見解乃為私法關係 人民經許可於公有道路作特殊使用，其利用關係屬公法關係 公有道路通車開放使用為一般處分', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
